#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10;

int n,f[N],son[N*61][2],tot,u,v,stk[N],top;
vector<int> e[N];
long long a[N],ans[N],res;

int New(){
    tot++;
    son[tot][0]=son[tot][1]=0;
    return tot;
}

void Insert(int x){
    int p=1;
    for(int i=59;i>=0;i--){
        if(!son[p][(a[x]>>i)&1]) son[p][(a[x]>>i)&1]=New();
        p=son[p][(a[x]>>i)&1];
    }
    son[p][0]=x;
}

int query(long long num){
    int p=1;
    for(int i=59;i>=0;i--){
        int s=((num>>i)&1);
        if(son[p][!s]) p=son[p][!s];
        else p=son[p][s];
    }
    return son[p][0];
}

void dfs(int x){
    Insert(x);
    res=max(res,a[x]^a[query(a[x])]);
    for(int y:e[x])
        dfs(y);

}

int main(){
    scanf("%d",&n);
    for(int i=2;i<=n;i++){
        scanf("%d",&f[i]);
        e[f[i]].push_back(i);
    }
    tot=1;
    for(int i=1;i<=n;i++){
        scanf("%lld",&a[i]);
        Insert(i);
        int p=query(a[i]);
        if((a[p]^a[i])>=res)
            res=(a[p]^a[i]),u=p,v=i;
    }
    //printf("%lld %lld\n",a[u]^a[v],res);
    memset(ans,-1,sizeof(ans));
    res=0,tot=0;
    New();
    for(int i=u;i;i=f[i]) stk[++top]=i;
    for(int i=top;i;i--){
        int x=stk[i];
        ans[x]=res;
        Insert(x);
        res=max(res,a[x]^a[query(a[x])]);
        for(int y:e[x])
            if(y!=stk[i-1])
                dfs(y);
    }
    res=0,tot=0,top=0;
    New();
    for(int i=v;i;i=f[i]) stk[++top]=i;
    for(int i=top;i;i--){
        int x=stk[i];
        ans[x]=res;
        Insert(x);
        res=max(res,a[x]^a[query(a[x])]);
        for(int y:e[x])
            if(y!=stk[i-1])
                dfs(y);
    }
    for(int i=1;i<=n;i++)
        if(~ans[i])
            printf("%lld\n",ans[i]);
        else
            printf("%lld\n",a[u]^a[v]);
    return 0;
}
